
DROP TABLE IF EXISTS students;

CREATE TABLE students (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    student_name TEXT,
    student_age INTEGER,
    student_gender TEXT,
    nationality TEXT,
    religion TEXT,
    student_order TEXT,
    student_class TEXT,
    student_stream INTEGER,
    entry_year INTEGER,
    student_adm_number TEXT,
    student_code TEXT,
    color TEXT,
    father_name TEXT,
    father_occupation TEXT,
    father_contact TEXT,
    father_alt_contact TEXT,
    mother_name TEXT,
    mother_occupation TEXT,
    mother_contact TEXT,
    mother_alt_contact TEXT,
    guardian_name TEXT,
    guardian_occupation TEXT,
    guardian_contact TEXT,
    guardian_alt_contact TEXT,
    residential_area TEXT,
    zone TEXT,
    road TEXT,
    health_problem TEXT,
    emergency_person TEXT,
    other_information TEXT,
    date_of_birth TEXT,
    image TEXT,
    registration_date TEXT,
    created_by TEXT
);

